// POST /token - Exchange authorization code for tokens
app.post('/token', (req, res) => {
  const { grant_type, code, redirect_uri, client_id, client_secret, refresh_token } = req.body;

  // Also support client credentials in Authorization header
  let authenticatedClientId = client_id;
  let authenticatedClientSecret = client_secret;

  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString();
    const [headerClientId, headerClientSecret] = decoded.split(':');
    authenticatedClientId = authenticatedClientId || headerClientId;
    authenticatedClientSecret = authenticatedClientSecret || headerClientSecret;
  }

  // Validate client credentials
  const client = clients[authenticatedClientId];
  if (!client || client.client_secret !== authenticatedClientSecret) {
    return res.status(401).json({
      error: 'invalid_client',
      error_description: 'Client authentication failed'
    });
  }

  if (grant_type === 'authorization_code') {
    return handleAuthorizationCodeGrant(req, res, client, code, redirect_uri);
  } else if (grant_type === 'refresh_token') {
    return handleRefreshTokenGrant(req, res, client, refresh_token);
  } else {
    return res.status(400).json({
      error: 'unsupported_grant_type',
      error_description: 'Only "authorization_code" and "refresh_token" grant types are supported'
    });
  }
});

function handleAuthorizationCodeGrant(req, res, client, code, redirect_uri) {
  if (!code) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Authorization code is required'
    });
  }

  const authCode = authorizationCodes[code];

  // Validate authorization code exists
  if (!authCode) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid authorization code'
    });
  }

  // Check if code has already been used (prevent replay attacks)
  if (authCode.used) {
    // Revoke any tokens issued with this code
    console.log(`[SECURITY] Authorization code reuse detected: ${code}. Revoking associated tokens.`);
    delete authorizationCodes[code];
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has already been used'
    });
  }

  // Check if code has expired
  if (Date.now() > authCode.expiresAt) {
    delete authorizationCodes[code];
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code has expired'
    });
  }

  // Validate client_id matches
  if (authCode.client_id !== client.client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Authorization code was not issued to this client'
    });
  }

  // Validate redirect_uri matches
  if (redirect_uri && authCode.redirect_uri !== redirect_uri) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'redirect_uri does not match the one used in the authorization request'
    });
  }

  // Mark code as used
  authCode.used = true;

  // Generate tokens
  const accessToken = generateToken(32);
  const newRefreshToken = generateToken(32);
  const expiresIn = 3600; // 1 hour

  // Store access token
  accessTokens[accessToken] = {
    token: accessToken,
    client_id: client.client_id,
    username: authCode.username,
    scope: authCode.scope,
    expiresAt: Date.now() + expiresIn * 1000
  };

  // Store refresh token
  refreshTokens[newRefreshToken] = {
    token: newRefreshToken,
    client_id: client.client_id,
    username: authCode.username,
    scope: authCode.scope,
    expiresAt: Date.now() + 30 * 24 * 60 * 60 * 1000 // 30 days
  };

  console.log(`[TOKEN] Access token issued for user: ${authCode.username}, client: ${client.client_id}`);

  // Return tokens
  res.json({
    access_token: accessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: newRefreshToken,
    scope: authCode.scope
  });
}

function handleRefreshTokenGrant(req, res, client, refreshToken) {
  if (!refreshToken) {
    return res.status(400).json({
      error: 'invalid_request',
      error_description: 'Refresh token is required'
    });
  }

  const storedRefreshToken = refreshTokens[refreshToken];

  if (!storedRefreshToken) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Invalid refresh token'
    });
  }

  if (Date.now() > storedRefreshToken.expiresAt) {
    delete refreshTokens[refreshToken];
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token has expired'
    });
  }

  if (storedRefreshToken.client_id !== client.client_id) {
    return res.status(400).json({
      error: 'invalid_grant',
      error_description: 'Refresh token was not issued to this client'
    });
  }

  // Revoke old refresh token (rotation)
  delete refreshTokens[refreshToken];

  // Generate new tokens
  const newAccessToken = generateToken(32);
  const newRefreshToken = generateToken(32);
  const expiresIn = 3600;

  accessTokens[newAccessToken] = {
    token: newAccessToken,
    client_id: client.client_id,
    username: storedRefreshToken.username,
    scope: storedRefreshToken.scope,
    expiresAt: Date.now() + expiresIn * 1000
  };

  refreshTokens[newRefreshToken] = {
    token: newRefreshToken,
    client_id: client.client_id,
    username: storedRefreshToken.username,
    scope: storedRefreshToken.scope,
    expiresAt: Date.now() + 30 * 24 * 60 * 60 * 1000
  };

  console.log(`[TOKEN] Access token refreshed for user: ${storedRefreshToken.username}, client: ${client.client_id}`);

  res.json({
    access_token: newAccessToken,
    token_type: 'Bearer',
    expires_in: expiresIn,
    refresh_token: newRefreshToken,
    scope: storedRefreshToken.scope
  });
}

// Token introspection middleware
function authenticateToken(req, res, next) {
  const authHeader = req.headers.authorization;
  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'No bearer token provided' });
  }

  const token = authHeader.slice(7);
  const tokenData = accessTokens[token];

  if (!tokenData) {
    return res.status(401).json({ error: 'invalid_token', error_description: 'Invalid access token' });
  }

  if (Date.now() > tokenData.expiresAt) {
    delete accessTokens[token];
    return res.status(401).json({ error: 'invalid_token', error_description: 'Access token has expired' });
  }

  req.tokenData = tokenData;
  req.user = users[tokenData.username];
  next();
}

