// Token revocation endpoint
app.post('/revoke', (req, res) => {
  const { token, token_type_hint } = req.body;

  if (!token) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Token is required' });
  }

  // Try to revoke as access token
  if (accessTokens[token]) {
    delete accessTokens[token];
    console.log(`[REVOKE] Access token revoked: ${token.substring(0, 8)}...`);
  }

  // Try to revoke as refresh token
  if (refreshTokens[token]) {
    delete refreshTokens[token];
    console.log(`[REVOKE] Refresh token revoked: ${token.substring(0, 8)}...`);
  }

  // Always return 200 per RFC 7009
  res.status(200).json({ message: 'Token revoked successfully' });
});

// Token introspection endpoint (RFC 7662)
app.post('/introspect', (req, res) => {
  const { token } = req.body;

  if (!token) {
    return res.status(400).json({ error: 'invalid_request' });
  }

  const tokenData = accessTokens[token];
  if (tokenData && Date.now() < tokenData.expiresAt) {
    return res.json({
      active: true,
      scope: tokenData.scope,
      client_id: tokenData.client_id,
      username: tokenData.username,
      token_type: 'Bearer',
      exp: Math.floor(tokenData.expiresAt / 1000),
      iat: Math.floor((tokenData.expiresAt - 3600 * 1000) / 1000)
    });
  }

  res.json({ active: false });
});

