// Cleanup expired tokens periodically
setInterval(() => {
  const now = Date.now();
  let cleaned = 0;

  for (const [code, data] of Object.entries(authorizationCodes)) {
    if (now > data.expiresAt) {
      delete authorizationCodes[code];
      cleaned++;
    }
  }

  for (const [token, data] of Object.entries(accessTokens)) {
    if (now > data.expiresAt) {
      delete accessTokens[token];
      cleaned++;
    }
  }

  for (const [token, data] of Object.entries(refreshTokens)) {
    if (now > data.expiresAt) {
      delete refreshTokens[token];
      cleaned++;
    }
  }

  if (cleaned > 0) {
    console.log(`[CLEANUP] Removed ${cleaned} expired entries`);
  }
}, 60 * 1000); // Run every minute

